    "inlineSchema": "// Twynd App - Prisma Schema\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============ USER & AUTH ============\n\nenum AuthProvider {\n  EMAIL\n  GOOGLE\n  FACEBOOK\n  TIKTOK\n}\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n  PREFER_NOT_TO_SAY\n}\n\nmodel User {\n  id             String       @id @default(cuid())\n  email          String       @unique\n  authProvider   AuthProvider\n  authProviderId String?      @unique\n\n  // Public identity (used for room invitations and chat display)\n  nickname String?\n  avatar   String?\n\n  // Room & Connection\n  currentRoom         Room?   @relation(\"UserRoom\", fields: [currentRoomId], references: [id], onDelete: SetNull)\n  currentRoomId       String? @unique\n  connectionPartner   User?   @relation(\"UserConnections\", fields: [connectionPartnerId], references: [id], onDelete: SetNull)\n  connectionPartnerId String? @unique\n  partnerConnection   User?   @relation(\"UserConnections\")\n\n  isRoomLead Boolean @default(false)\n\n  // Room Membership\n  roomMemberships RoomMember[]\n\n  // Chat\n  sentMessages Message[] @relation(\"SenderMessages\")\n\n  // Subscription\n  subscription Subscription?\n\n  // Tracking\n  lastActiveAt DateTime @default(now())\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([email])\n  @@index([currentRoomId])\n  @@index([connectionPartnerId])\n}\n\n// ============ ROOMS ============\n\nenum RoomStatus {\n  WAITING_FOR_PARTNER\n  ACTIVE\n  COMPLETED\n  ARCHIVED\n}\n\nmodel Room {\n  id        String  @id @default(cuid())\n  code      String  @unique // Link/code for joining\n  qrCodeUrl String? // URL to QR code image\n\n  status RoomStatus @default(WAITING_FOR_PARTNER)\n\n  lead       User?        @relation(\"UserRoom\")\n  members    RoomMember[]\n  milestones Milestone[]\n\n  chatSessions ChatSession[]\n  insights     AIInsight[]\n\n  // Tracking\n  createdAt     DateTime  @default(now())\n  roomStartedAt DateTime? // When both users connected\n  updatedAt     DateTime  @updatedAt\n\n  @@index([code])\n  @@index([status])\n  @@index([createdAt])\n}\n\nenum RoomMemberRole {\n  LEAD\n  FOLLOWER\n}\n\nmodel RoomMember {\n  id     String         @id @default(cuid())\n  room   Room           @relation(fields: [roomId], references: [id], onDelete: Cascade)\n  roomId String\n  user   User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId String\n  role   RoomMemberRole\n\n  joinedAt DateTime @default(now())\n\n  @@unique([roomId, userId])\n  @@index([roomId])\n  @@index([userId])\n}\n\nmodel RoomAccess {\n  id           String    @id @default(cuid())\n  code         String    @unique // QR code / link\n  createdAt    DateTime  @default(now())\n  expiresAt    DateTime?\n  usedAt       DateTime?\n  usedByUserId String?\n\n  @@index([code])\n}\n\n// ============ CHAT & MESSAGING ============\n\nmodel ChatSession {\n  id     String @id @default(cuid())\n  room   Room   @relation(fields: [roomId], references: [id], onDelete: Cascade)\n  roomId String\n\n  gameType String? // e.g., \"love_map_builder\", \"this_or_that\"\n  title    String  @default(\"Chat\")\n\n  messages Message[]\n\n  // Milestone back-link\n  milestone Milestone? @relation(\"MilestoneChat\")\n\n  // Game Results\n  results Json? // Flexible JSON for game results\n\n  lastMessageAt DateTime?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  @@index([roomId])\n  @@index([lastMessageAt])\n}\n\nmodel Message {\n  id            String      @id @default(cuid())\n  chatSession   ChatSession @relation(fields: [chatSessionId], references: [id], onDelete: Cascade)\n  chatSessionId String\n\n  sender   User   @relation(\"SenderMessages\", fields: [senderId], references: [id], onDelete: Cascade)\n  senderId String\n\n  content     String @db.Text\n  contentType String @default(\"text\") // \"text\", \"reaction\", \"game_result\"\n\n  isRead Boolean   @default(false)\n  readAt DateTime?\n\n  reactions    Message[] @relation(\"MessageReactions\")\n  reactionTo   Message?  @relation(\"MessageReactions\", fields: [reactionToId], references: [id], onDelete: SetNull)\n  reactionToId String?\n\n  createdAt DateTime @default(now())\n\n  @@index([chatSessionId])\n  @@index([senderId])\n  @@index([createdAt])\n}\n\n// ============ SUBSCRIPTION & BILLING ============\n\nenum SubscriptionStatus {\n  ACTIVE\n  EXPIRED\n  CANCELLED\n}\n\nmodel Subscription {\n  id     String @id @default(cuid())\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId String @unique\n\n  status    SubscriptionStatus @default(ACTIVE)\n  startDate DateTime\n  endDate   DateTime\n\n  // Free trial info\n  isTrialPeriod  Boolean   @default(true)\n  trialStartDate DateTime?\n  trialEndDate   DateTime?\n\n  // Referrals (max 3, each qualifying referral = +30 days room extension)\n  referralCode          String   @unique @default(cuid())\n  referralCount         Int      @default(0)\n  referralExtensionDays Int      @default(0)\n  referralGeneratedAt   DateTime @default(now()) // When current link was last generated\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n}\n\n// ============ MILESTONES ============\n\nenum MilestoneType {\n  DAYS_7\n  DAYS_30\n  FEEL_GOOD_COUPLE\n  RECONCILED_COUPLE\n  CUSTOM\n}\n\nmodel Milestone {\n  id     String @id @default(cuid())\n  room   Room   @relation(fields: [roomId], references: [id], onDelete: Cascade)\n  roomId String\n\n  type           MilestoneType\n  milestoneTitle String\n  description    String?\n\n  aiGeneratedPoem String?\n\n  // Linked chat session for discussing this milestone\n  chatSession   ChatSession? @relation(\"MilestoneChat\", fields: [chatSessionId], references: [id], onDelete: SetNull)\n  chatSessionId String?      @unique\n\n  // Share consent (lead and follower must both agree before sharing)\n  leadConsentToShare     Boolean @default(false)\n  followerConsentToShare Boolean @default(false)\n\n  awardedAt DateTime @default(now())\n\n  @@index([roomId])\n}\n\n// ============ AI INSIGHTS ============\n\nmodel AIInsight {\n  id     String @id @default(cuid())\n  room   Room   @relation(fields: [roomId], references: [id], onDelete: Cascade)\n  roomId String\n\n  relationshipMetrics Json // RelationshipMetrics\n  interestMetrics     Json // InterestMetrics\n  sparkMetrics        Json // SparkMetrics\n  summaryText         String @db.Text\n\n  generatedAt DateTime @default(now())\n\n  @@index([roomId])\n  @@index([generatedAt])\n}\n",
